var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"크윽...!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"咳……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_07"},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"무의미한 공격이구나.","JPN":"無意味な攻撃だな。","ENG":"That attack was pointless.","TWN":"毫無意義的攻擊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"그런 감정에 치우친 힘으로는 날 막지 못한다.","JPN":"そのような感情任せの攻撃で我を止めることはできん。","ENG":"You can't stop me with power clouded by such emotions.","TWN":"那種被情感左右的力量，不可能阻止我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"헉!","JPN":"はっ！","ENG":"*Gasp!*","TWN":"呃！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"젠장... 또 실패인가?","JPN":"くそ……また失敗か？","ENG":"Damn it... We failed again?","TWN":"可惡……又失敗了嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"나가는 거니?","JPN":"また出かけるのかい？","ENG":"Heading out?","TWN":"你要出門嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아침 일찍부터 바쁘구나.","JPN":"朝から忙しいのね。","ENG":"You're busy early in the morning.","TWN":"一大早就這麼忙啊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...네. 해야 할 일이 있어서요.","JPN":"……うん。やることがあって。","ENG":"...Yes. I have something I need to do.","TWN":"……嗯，我有事情要做。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"해야 할 일이라...","JPN":"やることね……","ENG":"Something you need to do...","TWN":"有事情要做啊……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"모든 소망을 이뤄주는 낙원에서조차 그런 걸 찾는 거니?","JPN":"すべての望みを叶えてくれる楽園に来てまで、そういうことを探しているの？","ENG":"Even in the Promised Land that grants every wish, you're still looking for something like that?","TWN":"就算在這個能實現所有願望的樂園裡，你還是能找到要做的事嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"제 소망은 여기에 있어요.","JPN":"私の願いはここにあるわ。","ENG":"My wish is here.","TWN":"我的願望就在這裡。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 그 소망에 필요한 대가가 무엇인지 알고 나니-","JPN":"でも、その願いを叶えるための代償を知ってしまったら……","ENG":"But once I learned what price that wish required...","TWN":"但當我知道這個願望需要付出什麼代價後—"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이대로 안주하기 보단, 뭐라도 해야겠단 생각이 들더라고요.","JPN":"現状に満足しないで、何かやらなきゃって思えて。","ENG":"I couldn't just settle for this. I felt like I had to do something.","TWN":"就覺得不能只是待在這裡享受，總該做點什麼。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"신기하기도 하지.","JPN":"不思議なものね。","ENG":"How curious.","TWN":"真奇妙。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"소망을 누릴 땐 꿈을 꾸는 듯 흐리멍덩하더니, 꿈에서 깨어나려는 지금은 눈에 생기가 도는구나.","JPN":"願いが叶ったときは夢を見ているようにぼんやりとしていたのに、夢から覚めようとしている今、あなたの目は生き生きとしている。","ENG":"When you were enjoying your wish, your eyes looked hazy, as if you were dreaming. But now that you're trying to wake from that dream, there's life in them again.","TWN":"沉浸在願望時，你的眼神就像在作夢般朦朧。現在你想從夢裡醒來，眼神反而變得有生氣了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"평생 꿈을 꾸는 게 나았을 거라고, 나중에 후회하게 되면 어쩌죠?","JPN":"一生夢を見ていたほうがよかったかもって、後悔することになったらどうしよう？","ENG":"What if I end up regretting later that it would've been better to keep dreaming forever?","TWN":"如果你之後後悔，覺得還不如一輩子作夢怎麼辦？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"나중 일은 나중에 생각하렴.","JPN":"未来のことはその時になって考えればいいわ。","ENG":"You can think about later when it comes.","TWN":"那是之後的事。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"미래는 꿈으로 꿀 수 있지만, 지금은 꿈이 대신할 수 없잖니.","JPN":"未来は夢でも見られるけど、今を夢の中で生きることはできないものね。","ENG":"The future can be dreamed about, but the present can't be replaced by one.","TWN":"或許可以作夢想著未來，但可不能讓夢取代現在。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"가볼게요.","JPN":"行ってきます。","ENG":"I'll be going.","TWN":"我走了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그럼 우린, 딸기나 따러 가볼까?","JPN":"じゃあ私たちはイチゴ狩りにでも行きましょうか。","ENG":"Then shall we go pick some strawberries?","TWN":"那我們去摘草莓吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응.","JPN":"うん。","ENG":"Sure.","TWN":"嗯。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"죽음과 순환의 연결성 검증.","JPN":"死と循環の連結性検証。","ENG":"Verification of the link between death and recurrence.","TWN":"死亡與循環的連結性驗證。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"53번째.","JPN":"53回目。","ENG":"53rd attempt.","TWN":"第53次。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"오늘은 혼자 오셨네요.","JPN":"今日は一人なんですね。","ENG":"You came alone today.","TWN":"今天只有你一個人來啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그렇게 됐어.","JPN":"……まあね。","ENG":"...I guess I did.","TWN":"……是啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이번엔 어떤 주민 분의 이야기를 들려드릴까요?","JPN":"今回はどんな住民の話をお聞かせしましょうか？","ENG":"What kind of story would you like to hear about the residents this time?","TWN":"這次要不要聽聽某位居民的故事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런 건, 이미 질릴 만큼 들었어.","JPN":"そんなものはもう聞き飽きたよ。","ENG":"I've already heard enough of those.","TWN":"那些我已經聽膩了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"누가 어디서 연주회를 했니, 여럿이 모여 꽃놀이를 다녀왔느니 같은 사소한 이야긴 나한테 별로 중요하지도 않거든.","JPN":"誰がどこで演奏会をしただの、みんなで花見に行ってきただの、そういうささいな話は私にとってはどうでもいいことなの。","ENG":"Stories about who held a concert somewhere or who went flower viewing together, those little things don't really matter to me.","TWN":"誰在哪裡開了演奏會、誰又一起去賞花之類的小事，對我來說根本不重要。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그러니, 이번엔 네 이야길 해보는 건 어때?","JPN":"……だから、今回は君の話をしてくれないかな？","ENG":"...So how about telling me yours this time?","TWN":"……那這次不如說說你的故事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"제 이야기요...?","JPN":"私の話ですか……？","ENG":"Mine...?","TWN":"我的故事……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"아하, 레아 씨도 가지치기에 관심이 생긴 거군요? 가르쳐드릴까요?","JPN":"そうか、レアさんも剪定に興味が湧いたんですね？　教えましょうか？","ENG":"Ah, I see. You've taken an interest in pruning too, Ms. Leah? Want me to teach you?","TWN":"啊哈，原來蕾亞也開始對修剪枝條有興趣了？要我教你嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"딱히 배울 필요가 있나? 그냥 가지를 잘라내는 일일 뿐인데.","JPN":"教わる必要ってあるの？　ただ枝を切るだけなのに。","ENG":"Do I really need to learn that? It's just a matter of cutting branches.","TWN":"這種事還需要學嗎？就只是剪掉樹枝而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그럼요. 아무 가지나 함부로 잘랐다간 멀쩡한 나무를 죽이게 될 테니까요.","JPN":"もちろんです。下手に切れば、元気だった木を枯らしてしまいますから。","ENG":"Of course. If you cut branches carelessly, you could end up killing a perfectly healthy tree.","TWN":"當然囉。要是亂剪，會把好好的樹害死。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"언젠 그냥 예쁜 햇살이 비치는 그늘을 만들고 싶어서 가지를 자르는 거라며?","JPN":"綺麗な木漏れ日を作りたいから剪定するって前に言ってたよね？","ENG":"Didn't you say before that you prune them to create a beautiful patch of shade where sunlight filters through?","TWN":"你不是說是為了做出漂亮、有陽光的樹蔭才剪枝的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"맞아요. 그러니 원하는 형태로 다듬되 나무를 죽이지 않는, 그 중간점을 찾는 게 중요한 거죠.","JPN":"そうです。だから好きな形に整えつつも木を傷つけない、その妥協点を探すのが大事なんです。","ENG":"That's right. That's why it's important to find the balance. Shaping it the way you want without killing it.","TWN":"沒錯。所以找到既能修剪出想要的形狀，又不會害死那棵樹的那個平衡點很重要。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...자신의 나무가 생애 가장 큰 열매를 맺기를 원하는, 그 여자처럼요.","JPN":"……自分の木に、生涯で最も大きな実がなってほしいと願う、あの女のように。","ENG":"...Just like that woman who wanted her tree to bear the greatest fruit of its life.","TWN":"……就像那個希望自己的樹能結出一生最大果實的女人一樣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 여자?","JPN":"あの女？","ENG":"That woman?","TWN":"那個女人？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"레아 씨는 이곳에서의 삶이 행복하지 않나요?","JPN":"レアさんは、ここでの生活は幸せじゃないんですか？","ENG":"Aren't you happy living here?","TWN":"蕾亞，你在這裡的生活不幸福嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"글쎄.","JPN":"どうかな。","ENG":"I don't know.","TWN":"有可能。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"부족함을 느끼지 않는 게 행복이라면, 행복한 게 맞겠네.","JPN":"欠乏を感じないことが幸せだというなら、多分幸せだろうね。","ENG":"If happiness means not feeling any lack, then I suppose I am happy.","TWN":"如果不覺得缺少什麼就是幸福，那應該算幸福吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"우리 엄마도, 클라라도, 매일매일이 되풀이되는 이곳이라면 평생 행복하게 지낼 수 있을 거야.","JPN":"お母さんもクララも、毎日が繰り返されるここでなら、一生幸せに暮らせる。","ENG":"If they could stay somewhere like this, where every day repeats the same way, my mother and Clara could probably live happily forever.","TWN":"我媽媽、克拉拉，如果在這個每天都一樣的地方，大概一輩子都能幸福生活。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만...","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"거기에 어떤 대가가 필요하다면, 얘기가 달라져.","JPN":"そこになにか代償が必要とされるなら、話が違ってくる。","ENG":"If there's a price that has to be paid for it, then that changes things.","TWN":"如果那需要付出某種代價，事情就不同了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"적어도 난 그 대가를 외면하면서, 내 행복만 쫓고 싶지 않거든.","JPN":"私はその代償から目を背けて、自分の幸せばかり追いかけたくないの。","ENG":"At the very least, I don't want to chase only my own happiness while turning away from that price.","TWN":"至少我不想無視那個代價，只顧追求自己的幸福。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"변명하지 않을게요. 이 낙원을 유지하기 위해 양분이 필요한 건 사실이니까.","JPN":"言い訳はしません。この楽園を維持するために養分が必要なのは事実ですから。","ENG":"I won't make excuses. It's true that nutrients are needed to maintain the Promised Land.","TWN":"我不會找藉口。為了維持這個樂園，確實需要養分。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"좋은 열매를 맺기 위해 잘라내야 했던 가지들처럼, 원하는 결과를 얻으려면 다른 무언가를 희생해야 하는 법이거든요.","JPN":"良質の実がなるためには枝を切り落とさねばならないように、望む結果を手に入れるためには何かを犠牲にしなければなりません。","ENG":"Just like branches that must be cut for a tree to bear good fruit, achieving the result you want always requires sacrificing something else.","TWN":"就像為了讓樹結出好果實必須剪掉枝條，想得到某個結果，就必須犧牲其他東西。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"의미심장하네.","JPN":"意味深な表現だね。","ENG":"That sounds rather ominous.","TWN":"真意味深長呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"잘라내야 했던 가지라는 건, 낙원을 위해 양분이 된 세계를 말하는 건가?","JPN":"切り落とさなきゃならない枝ってのは、楽園の養分になった世界のことかな？","ENG":"By branches that had to be cut... do you mean the worlds that became nutrients for the Promised Land?","TWN":"你說的被剪掉的枝條，是指那些成為樂園養分的世界嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"모든 건 한 송이의 꽃에서 시작됐어요.","JPN":"すべては一輪の花から始まりました。","ENG":"Everything began with a single flower.","TWN":"一切都從一朵花開始。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"마왕 타기리온이 탐미엘의 뜻을 따르는 동안, 마왕의 나약했던 부분일 뿐인 전 어둠 속에 남겨진 채 그녀의 행보를 지켜 보고만 있었죠.","JPN":"魔王タギリオンがタミエルの意志に従う間、魔王の弱い部分にすぎなかった私は、闇の中に取り残されたまま彼女の行動をただ見守っていました。","ENG":"While Demon Lord Thagirion followed Tammiel's will, I remained behind in the darkness, nothing more than the Demon Lord's weakness, forced to watch her from afar.","TWN":"當魔王塔基里翁遵從塔米爾的意志時，我只是魔王軟弱的那一部分。被留在黑暗裡，只能看著她的行動。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그러던 어느 날, 제 곁에 꽃 한 송이가 피어난 거예요.","JPN":"そんなある日、私のそばに一輪の花が咲いたのです。","ENG":"Then one day, a single flower bloomed beside me.","TWN":"直到某一天，我身邊開出了一朵花。"},"stage":{"bg":"SKY","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그 다음날엔 나무 한 그루가 자라있었고, 그 다음날엔 햇빛을 머금어 반짝이는 호수가 펼쳐졌죠.","JPN":"次の日には一本の木が生え、その次の日は太陽に照らされて煌めく湖が広がりました。","ENG":"The next day, a tree had grown there. The day after that, a lake shimmering with sunlight spread out before me.","TWN":"隔天長出了一棵樹。再過一天，一片倒映著陽光、閃閃發亮的湖泊出現了。"},"stage":{"bg":"SKY","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그렇게 봄의 따스함을 느끼기 시작할 무렵이 되자, 과거 알고 지내던 마을사람들과 언니가 제 곁으로 돌아와 있었어요.","JPN":"そうやって春の温もりを感じる頃になると、過去に知り合った村人やお姉ちゃんが私のそばに戻ってきていました。","ENG":"And by the time I could begin to feel the warmth of spring, the villagers I once knew and my sister had returned to my side.","TWN":"等到我開始感受到春天的溫暖時，以前認識的村民和姐姐，也回到了我身邊。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이해해. 얼마나 지났을지 모르는 세월을 어둠 속에만 갇혀있다가 세상을 돌려받는 기분은, 정말 각별했겠네.","JPN":"分かるよ。気が遠くなる程の年月を闇の中だけで過ごした後に、ようやく世界が自分の元に返ってきた時の気持ち。本当に格別だっただろうね。","ENG":"I understand. After being trapped in darkness for who knows how long, it must have felt truly special to have the world returned to you.","TWN":"我懂。被困在黑暗裡不知過了多少歲月後，突然重新得到世界，那感覺一定很特別。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...마왕은 그것이 소녀가 마땅히 누려야 할 세상이라고만 말할 뿐, 그 낙원이 무엇을 대가로 생겨났는지에 대해선 말하지 않았어요.","JPN":"……魔王はただ、それは少女が享受すべき世界だと言うだけで、その楽園が何を代償として生まれたかについては語りませんでした。","ENG":"...The Demon Lord only said that this was the world a girl rightfully deserved to enjoy, and never spoke of what price had been paid to create the Promised Land.","TWN":"……魔王只說那是少女理應擁有的世界，卻沒有提到這個樂園是以什麼為代價誕生的。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그리고 소녀 역시 그 대가가 무엇인지 캐묻지 않았죠. 간신히 돌려받은 낙원, 그녀의 배려를 온전히 만끽할 뿐.","JPN":"そして少女もまた、代償について詮索することはありませんでした。ようやく返ってきた楽園……魔王の配慮をひたすら心ゆくまで満喫しました。","ENG":"And the girl never asked what that price was either. She simply enjoyed the Promised Land she had finally regained, accepting her kindness as it was.","TWN":"而少女也沒有去追問那個代價，只是盡情享受好不容易回來的樂園，以及她的體貼。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온은 이 낙원을 위해... 우리 세계도 양분으로 만들려는 거지?","JPN":"タギリオンはこの楽園のために……私たちの世界も養分にしようとしてるよね？","ENG":"Thagirion is trying to make our world into nutrients for the Promised Land too... isn't she?","TWN":"塔基里翁為了這個樂園……也想把我們的世界變成養分？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원은 양분을 얻을 때마다 완성되고 있어요. 더는 양분을 필요로 하지 않는 완벽한 세계의 완성을 코앞에 두고 있죠.","JPN":"楽園は養分を得るたびに完成に近づいています。これ以上養分を必要としない完璧な世界になるまで、あと少しです。","ENG":"The Promised Land is being completed each time it gains more nutrients. It's close to becoming a perfect world that no longer needs any more.","TWN":"每得到一份養分，樂園就離完成更近一步。距離那個再也不需要養分的完美世界，只剩最後一步了。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"아직 모든 걸 말할 순 없지만, 당신의 세계가 마지막이 되리란 것만은 확신해요.","JPN":"まだすべてをお話しすることはできませんが、間違いなくあなたの世界が最後になるでしょう。","ENG":"I can't tell you everything just yet, but I'm certain your world will be the last.","TWN":"我現在還不能告訴你一切，但我很確信，你們的世界會是最後一個。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"사람은 누구나 이기적으로 행동할 수 밖에 없는 순간이 있다고 생각해.","JPN":"自己中心的に行動するしかない瞬間って、誰にでもあると思うの。","ENG":"I think there are moments when anyone has no choice but to act selfishly.","TWN":"我認為人總會有不得不自私的時候。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고 사람과 사람 사이의 이기심이 엇갈리는 순간, 충돌은 피할 수 없게 되지.","JPN":"そして人と人のエゴがぶつかる瞬間、衝突は避けられなくなる。","ENG":"And when the selfishness between people crosses paths, conflict becomes unavoidable.","TWN":"而當人與人間的自私互相牴觸時，就無法避免衝突。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원을 없애고 싶으세요?","JPN":"楽園を消したいのですか？","ENG":"Do you wish to erase the Promised Land?","TWN":"你想毀掉樂園？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"꿈에서 깨어날 시간이 된 것 뿐이야.","JPN":"夢から覚める時間になっただけだよ。","ENG":"It's just time to wake up from the dream.","TWN":"只是該從夢裡醒來了。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"전 해가 저무는 광경을 좋아해요.","JPN":"私は日が暮れていく光景が好きです。","ENG":"I like the sight of the sun setting.","TWN":"我很喜歡夕陽西下的景色。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"특히 이 시간에 짙어지는 풀냄새가 마음을 편하게 해주거든요. 왜인지는 잘 모르겠지만요.","JPN":"特にこの時間になると草の匂いが濃くなって、心を落ち着かせてくれるんです。理由はよく分かりませんが。","ENG":"Especially the way the scent of grass grows stronger at this time, it puts my mind at ease. I don't really know why, though.","TWN":"雖然我也不知道為什麼，總覺得這個時間變得濃郁的草味，讓人很安心。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"곧 누군가 당신을 죽이러 올 텐데, 고작 풀 냄새에 마음이 편해진다고? 두렵지 않은 거야?","JPN":"もうすぐ誰かが君を殺しに来るのに、草の匂いで心を落ち着かせてる場合？　怖くないの？","ENG":"Someone will be coming to kill you soon, and the smell of grass is enough to put your mind at ease? Aren't you afraid?","TWN":"很快就會有人來殺你了，你還能因為草味而感到安心？不害怕嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원은 늘 그렇듯, 제 소망을 이뤄줄 뿐인 걸요.","JPN":"楽園はいつだって、私の願いを叶えてくれているだけですから。","ENG":"The Promised Land only ever grants my wish, as it always has.","TWN":"樂園只會一如既往實現我的願望。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아의 손에 죽는 게 소망이란 건, 그 죽음이 나름의 속죄이기 때문인가?","JPN":"エクレシアの手にかかって殺されることが願いだというのは、その死が君なりの贖罪だから？","ENG":"Is dying at Ecclesia's hands your wish because that death would be your way of atonement?","TWN":"被艾可露西亞殺死，是你的願望？因為那樣的死亡是一種贖罪嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"맞아요. 그리고 그 속죄라는 건 당사자의 마음은 안중에도 없는 저만의 위안일 뿐이죠.","JPN":"そうです。そしてその贖罪とは、本人たちの気持ちなどまったく気にしていない単なる私の自己満足です。","ENG":"Yes. And that atonement is nothing more than my own comfort, without any regard for how the other person feels.","TWN":"沒錯。但那所謂的贖罪，其實只是我自己的自我安慰，根本沒有考慮到當事人的心情。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"레아 씨도 아시다시피, 진짜 에클레시아 님은 저를 죽이려 하지 않을 테니까요.","JPN":"レアさんもご存知のとおり、本物のエクレシア様は私を殺そうとしないはずですから。","ENG":"As you know, the real Ecclesia would never try to kill me.","TWN":"蕾亞你也知道，真正的艾可露西亞不會想殺我。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그게 가짜라는 걸 알고 있다면...","JPN":"あれが偽物だって分かってるなら……","ENG":"If you know that's a fake...","TWN":"既然你知道那是假的……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"심지어 진짜 에클레시아는 오히려 널 구하려 한다는 걸 알고 있다면...! 그 가짜한테 죽는 게 무슨 의미가 있지?!","JPN":"しかも、本物のエクレシアは君を救おうとしてるって分かってるなら……！　あの偽物に殺されることに何の意味があるの！？","ENG":"And even know the real Ecclesia is actually trying to save you...! Then what meaning is there in dying to that fake?!","TWN":"甚至知道真正的艾可露西亞反而想救你……那被那個假貨殺死到底有什麼意義？！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그 질문에 제가 대답하는 건 별로 의미가 없을 거에요.","JPN":"その質問に私が答える必要はないでしょう。","ENG":"It wouldn't mean much for me to answer that question.","TWN":"我回答這個問題其實沒有什麼意義。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"황금나무의 예언이 틀리지 않았다면, 당신도 결국 그 진실을 알게 될 테니까.","JPN":"黄金の木の予言が間違っていなければ、あなたももうすぐ真実を知ることになりますから。","ENG":"If the Golden Tree's prophecy isn't wrong, then you'll eventually learn the truth yourself.","TWN":"如果黃金樹的預言沒錯，你終究也會知道真相。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"황금나무의... 예언이라고?","JPN":"黄金の木の……予言？","ENG":"The Golden Tree's... prophecy?","TWN":"黃金樹的……預言？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"늦어서 미안하구나, 아우드라.","JPN":"遅れてすまない、アウドラ。","ENG":"Sorry I'm late, Audra.","TWN":"抱歉來晚了，奧德拉。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"고통은 길지 않을 거다.","JPN":"苦しみはすぐに終わる。","ENG":"Your pain won't last long.","TWN":"痛苦不會持續太久。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아니. 늦지 않았어.","JPN":"ううん、遅れてなんかいないよ。","ENG":"No. You're not late.","TWN":"不，還不算太晚。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신은 언제나 아우드라가 원하는 순간에 나타나거든.","JPN":"君はいつだって、アウドラが望む瞬間に現れるから。","ENG":"You always appear at the moment Audra wants you to.","TWN":"因為你總在奧德拉需要的那刻出現。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"넌 누구지?","JPN":"そなたは誰だ？","ENG":"Who are you?","TWN":"你是誰？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아우드라를 죽이려는 당신을 막으려는 사람.","JPN":"アウドラを殺そうとする君を止めようとする人。","ENG":"Someone who intends to stop you from killing Audra.","TWN":"阻止你殺死奧德拉的人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"어리석구나. 저 아이의 정체를 모르는 건가?","JPN":"愚かな。あの子の正体を知らないのか？","ENG":"How foolish. Do you not know what that child truly is?","TWN":"愚蠢。難道你不知道那孩子的真實身分嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"알아.","JPN":"知ってるよ。","ENG":"I do.","TWN":"我知道。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"자기 언니의 죽음을 계기로 마왕이 되어 엘리시온을 멸망 시킬 운명의 가련한 소녀지.","JPN":"姉の死をきっかけに魔王になって、エリシオンを滅ぼす運命にある、哀れな少女。","ENG":"A pitiful girl destined to become the Demon Lord and destroy Elysion after her sister's death.","TWN":"因為自己姐姐死亡而成為魔王、最終將毀滅艾利森，命運悲慘的少女。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"그 모든 전말을 알고 있다면, 왜 나를 막겠다는 거냐.","JPN":"それを知っていて、なぜ我を止めようとする？","ENG":"If you know all that, then why would you try to stop me?","TWN":"既然你知道整個來龍去脈，為什麼還要阻止我？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"실험해보고 싶은 게 있거든.","JPN":"試したいことがあるの。","ENG":"There's something I want to test.","TWN":"因為我有件事想實驗看看。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"실험이라고?","JPN":"試す？","ENG":"Test?","TWN":"實驗？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신이 저 녀석을 죽이는 데 실패하면, 어떤 일이 벌어지는지.","JPN":"君があの子を殺すことに失敗したら、どんなことが起きるのか。","ENG":"What happens if you fail to kill her.","TWN":"如果你沒能殺死那傢伙，會發生什麼事。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"...어리석군.","JPN":"……愚かな。","ENG":"...You really are foolish.","TWN":"……真愚蠢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"네 뜻이 정 그러하다면-","JPN":"それがそなたの望みだというのなら……","ENG":"If that is truly your will...","TWN":"既然你這麼堅持—"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"크레모아다. 늘 똑같은 장소에서 나타나길래 미리 숨겨뒀...","JPN":"クレイモアだよ。いつも同じ場所から現れるから、事前に隠して……","ENG":"It's a claymore. Since you always appear in the same place, I hid it there in advance–","TWN":"是闊刀地雷。每次都在同一個地方出現，我就提前埋在這裡……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐야...? 멀쩡하다고?","JPN":"どういうこと……？　なんともないなんて？","ENG":"What...? You're unharmed?","TWN":"什麼……？竟然沒事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"성자인가. 신묘한 수법을 쓰는군.","JPN":"聖者か。神妙な手を使ってくるものだ。","ENG":"A Helgon, are you? You use curious tricks.","TWN":"是聖者嗎？真是神妙的手段。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"허나, 그대가 사술을 예비하고 있음은 그 은밀한 손동작과 지면에서 약동하는 전류의 흐름으로 파악하였으니.","JPN":"しかしそなたが邪術を用意していることは、密かな手の動きと地面から躍動する電流の流れで把握済みだ。","ENG":"However, I perceived that you had prepared sorcery through your subtle hand movement and the current stirring along the ground.","TWN":"不過從你細微的手勢和地面隱約跳動的電流，就能看出你準備施展邪術。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"격발 스위치 누르는 걸 보고 반응했다고?","JPN":"撃発スイッチを押すのを見て、動いたってこと？","ENG":"You reacted just from seeing me press the trigger switch?","TWN":"你是看我按下引爆開關才反應過來的？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그럼 이건 어때!","JPN":"……じゃあこれはどう！","ENG":"...Then how about this!","TWN":"……那這個呢！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"정면승부는 피하고 잔재주를 부리는가.","JPN":"真っ向勝負を避け、小細工を弄するか。","ENG":"Avoiding a direct confrontation and relying on tricks instead?","TWN":"不敢正面對決，只會耍小手段啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"그리 멀리 가진 못하리라.","JPN":"そう遠くまで行けると思うな。","ENG":"You won't get far.","TWN":"你逃不了多遠的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"잠... 따라붙는 속도가 무슨...!","JPN":"まっ……なんて速さ……！","ENG":"Wait– how are you closing the distance so fast...!","TWN":"等等……你追上來的速度也太……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_03"},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"콜록 콜록... 젠장.","JPN":"ゲホッ、ゲホッ……くそ。","ENG":"*Cough* *Cough...* Damn it.","TWN":"咳咳……可惡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_10"},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"유인하려다 나까지 휘말릴 뻔했네.","JPN":"おびき寄せようとして自分も巻き込まれるとこだった。","ENG":"I almost got caught in my own trap trying to lure you in.","TWN":"本來想把他引過來，結果差點把自己也捲進去。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래도 이 정도 폭발이라면...","JPN":"でもこれくらいの爆発なら……","ENG":"Still, with an explosion like that...","TWN":"不過這種程度的爆炸……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭣...?","JPN":"なっ……？","ENG":"What...?","TWN":"什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"CRF... 집약 기관?","JPN":"CRF……集約機関？","ENG":"A CRF... focusing unit?","TWN":"CRF……聚能機構？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래. 네가 쓰는 무기를 살펴봤는데, 그건 단순히 소형화된 레일건이 아니었어.","JPN":"そう。君が使っている武器を見たけど、あれは単純に小型化されたレールガンじゃなかった。","ENG":"That's right. I examined the weapon you're using, and it's not just a miniaturized railgun.","TWN":"沒錯。我研究過你的武器，那並不只是縮小版的電磁炮。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"카운터 특화 장비... 그러니까 성자가 자신의 힘을 담을 수 있도록 만들어진 무기인 거지. 내가 관리해본 압류품 중에도 그런 게 있었거든.","JPN":"カウンター特化装備……つまり聖者が自分の力を込められるように作られた武器ってこと。私が管理していた押収品の中にも似たようなものがあったから、知ってるんだ。","ENG":"It's Counter-specialized gear. In other words, a weapon designed so a Helgon can channel her power into it. I've handled confiscated items like that before.","TWN":"那是制裁者專用裝備……也就是能讓聖者注入自身力量的武器。我在曾經管理過的沒收物品中也見過這種東西。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그런데 그것이, 오늘 소녀가 레아 님과 함께 가지 않는 것과 무슨 상관이옵니까...?","JPN":"ですが、それが今日、わたくしとレア様が行動を共にしないこととはどう関係があるのでございますか……？","ENG":"But what does that have to do with me not going with you today, Ms. Leah...?","TWN":"但那和我今天沒有跟蕾亞一起走有什麼關係……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"지금까지 싸워본 경험 상, 그 녀석은 우리의 움직임을 모두 간파했어.","JPN":"今まで戦った経験からすると、あいつは私たちの動きを全部看破してる。","ENG":"From my experience fighting that thing so far, it's seen through all of our movements.","TWN":"根據我們至今的戰鬥經驗，那傢伙能看穿我們所有行動。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 그 무기는 녀석이 감지할 수 없을 정도로 먼 곳에서도 닿을 수 있거든.","JPN":"でも君の武器は、やつが感知できないほど遠い距離からでも届くの。","ENG":"But that weapon can reach it even from far beyond the distance it can detect.","TWN":"但這把武器，能從他感知不到的遠距離命中他。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 녀석을 한 장소에 최대한 오래 묶어볼게. 넌 네가 가진 힘을 담아 최강의 한 방을 날려.","JPN":"私がやつを一所になるべく長く足止めしてみる。君は君の力を込めて最強の一発を撃って。","ENG":"I'll keep it pinned in one place as long as possible. You pour all the power you have into it and fire your strongest shot.","TWN":"我會盡量拖住他，讓他在同一個地方久一點。你灌入自己所有力量，釋放最強的一擊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"최강의 한 방...","JPN":"最強の一発……","ENG":"My strongest shot...","TWN":"最強的一擊……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"소녀가 성자라곤 하나... 그런 힘을 쓸 자질이 있는진 모르옵니다.","JPN":"わたくしは聖者だと言われますが……そのような力を使う素質があるかどうか分かりません。","ENG":"Even if I am a Helgon... I don't know if I have the aptitude to use that kind of power.","TWN":"雖然我是聖者……但我不知道自己是否有使用那種力量的資質。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"실패하면 다시 하면 돼.","JPN":"失敗したらやり直せばいいよ。","ENG":"If you fail, then try again.","TWN":"失敗了再來一次就好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고, 내가 아는 당신이라면 분명 해낼 수 있을 거야.","JPN":"それに、私の知ってる君なら、きっとやり遂げられる。","ENG":"And if it's you, the one I know, I'm sure you can do it.","TWN":"而且，如果是我認識的你，一定做得到。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...컥!","JPN":"……かはっ！","ENG":"...Kuh!","TWN":"……咳！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_05"},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"심장은 찌르지 않았으니, 다음 대답이 너의 생사를 결정지을 것이다.","JPN":"心臓は避けてやった。次の答えでそなたの命運が決まるであろう。","ENG":"I didn't strike your heart. Your next answer will decide whether you live or die.","TWN":"我沒有刺中心臟，你的下個回答會決定你的生死。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"고하라. 누가 너를 이끌었지?","JPN":"答えよ。誰がそなたを導いた？","ENG":"Speak. Who guided you here?","TWN":"說，是誰指使你的？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...틀렸어. 의식이... 흐릿해져 가...","JPN":"……駄目だ。意識が……遠くなっていく……","ENG":"...I was wrong. My consciousness is... fading...","TWN":"……不行了。意識……開始模糊了……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"누가 너에게 아우드라를 지킬 것을 종용하였나!","JPN":"誰がそなたにアウドラを守るよう促した！","ENG":"Who urged you to protect Audra?!","TWN":"是誰命令你守護奧德拉！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...이번에도... 실패인가...","JPN":"……今回も……失敗か……","ENG":"...I've failed... yet again...","TWN":"……這次……也失敗了嗎……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"엘리시움 필하모닉의... 마에스트로.","JPN":"エリシウムフィルハーモニーの……マエストロ。","ENG":"Maestra of Elysium Philharmonic...","TWN":"愛樂組織的……指揮家。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"...뭐라고?","JPN":"……何だと？","ENG":"...What did you say?","TWN":"……什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"우린 누군가의 지시로 당신을 막는 게 아니에요. 마에스트로의 실험이 우리 모두를 타락시켰기 때문이죠.","JPN":"私たちは誰かの指示であなたを止めようとしているわけではありません。マエストロの実験が私たちを堕落させたからです。","ENG":"We aren't stopping you under someone's orders. It's because Maestra's experiment corrupted us all.","TWN":"我們不是因為誰的命令才阻止你。而是因為指揮家的實驗，讓我們全部墮落了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"당신이 아우드라를 죽여야만 하는 이유도... 돌이켜보면, 결국 그자가 시작한 실험 때문이지 않나요?","JPN":"あなたがアウドラを殺さねばならない理由も……思い返してみれば、あの者が始めた実験のせいではありませんか？","ENG":"And the reason you must kill Audra as well... if you look back on it, isn't it because of the experiment she began?","TWN":"你必須殺死奧德拉的理由……仔細想想，不也是那個人開始的實驗造成的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"...멘탈 프린팅.","JPN":"……メンタル・プリンティング。","ENG":"...Mental Printing.","TWN":"……智力複印。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"그래요. 그 연구가 모든 것의 화근이었죠.","JPN":"そうです。その研究がすべての元凶でした。","ENG":"Yes. That research was the root of everything.","TWN":"沒錯，那項研究就是一切的禍端。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"빛 어둠도 분간 못하는 장님이 세상에서 가장 빛나는 존재를 동경하게 되면서 시작한 연구.","JPN":"光と闇の区別もつかない盲人が、世界で最も輝く存在に憧れて始めた研究。","ENG":"Research that began when a blind person who couldn't even distinguish light from darkness came to admire the brightest being in the world.","TWN":"一個分不清光與暗的盲人，憧憬著世上最耀眼存在而開始的研究。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"바로, 당신이 문제였답니다. 예하.","JPN":"すなわちあなたが問題だったのです、猊下。","ENG":"You were the problem from the very beginning, Your Eminence.","TWN":"問題的根源其實就是你，主教。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"넌...","JPN":"そなたは……","ENG":"You're...","TWN":"你是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"...네퀴티아?","JPN":"……ネキティアか？","ENG":"...Nequitia?","TWN":"……莉奎蒂亞？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"그토록 홀로 빛나고... 지고하며, 강인한 존재.","JPN":"どこまでも輝き……どこまでも高く、どこまでも強い、至高の存在。","ENG":"A being who shone alone... noble, and strong.","TWN":"那樣孤獨耀眼……崇高而強大的存在。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"그런 존재를 내 손으로 빗어낼 수 있기를 바라며 시작된 실험은... 첫 악장부터 도돌이표로 뒤덮인, 글러 먹은 음악이었죠.","JPN":"そのような存在を自分の手で作り出すことを夢見て始めた実験は……第1楽章からダ・カーポで埋め尽くされた、失敗作でした。","ENG":"The experiment that began with the wish that I might shape such a being with my own hands... was doomed music from the very first movement, covered in repeat marks.","TWN":"希望能親手創造那樣的存在而開始的實驗……從第一樂章開始就滿是反覆記號，是一首徹底失敗的樂曲。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"애초에 내가 본뜨려 했던 당신은... 순수한 인간이 아니었으니까요.","JPN":"そもそも私が象ろうとしたあなたは……純粋な人間ではありませんでしたから。","ENG":"Because the you I tried to imitate from the start... was never a pure human.","TWN":"因為我最初想模仿的你……本來就不是純粹的人類。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"무슨 말을 하는 거지?","JPN":"何を言っている？","ENG":"What are you saying?","TWN":"你在說什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"내가... 인간이 아니라고?","JPN":"我が……人間ではないだと？","ENG":"I'm... not human?","TWN":"我……不是人類？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"후후... 당신도, 마에스트로도, 참 어리석었어요.","JPN":"ふふ……あなたも、マエストロも、愚かでしたね。","ENG":"Haha... Both you and Maestra were truly foolish.","TWN":"呵呵……你和指揮家真是愚蠢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"정말로... 믿음을 통해 강해지는 성자가 있을 거라고 생각하다니.","JPN":"本当に……信仰で強くなる聖者がいると思い込むだなんて。","ENG":"To think there could really be a Helgon who grows stronger through belief.","TWN":"竟然真的相信會有因信仰而變強的聖者。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"사람들에게 기억되고 숭배 받음으로서 힘을 얻는 건... 영락없는 요정의 기질인데 말이죠.","JPN":"人々に記憶され、崇拝されることで力を得るのは……まごうことなき妖精の気質だというのに。","ENG":"Gaining power by being remembered and worshipped by people... that's unmistakably a fairy's nature.","TWN":"能因為被人記住、崇拜而獲得力量……那根本就是精靈的特質。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...정신이 아득해. 내가 무슨 말을 하고 있는 거지?","JPN":"……意識がはっきりしない。私は何を言ってるんだろう？","ENG":"...My mind is spinning. What am I saying?","TWN":"……意識好混亂。我到底在說什麼？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"방금 전에... 날 네퀴티아라고 부른 건가?","JPN":"さっき……私をネキティアって呼んだ？","ENG":"Just now... Did she call me Nequitia?","TWN":"剛剛……你叫我莉奎蒂亞？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"멘탈 프린팅 연구가 정체 되어 있을 때... 우연히 당신의 부친을 만난 적이 있어요.","JPN":"メンタル・プリンティング研究が停滞していた頃……偶然、あなたのお父様にお会いしたことがあります。","ENG":"When the Mental Printing research stalled... I happened to meet your father.","TWN":"當智力複印研究陷入停滯時……我曾偶然遇過你父親。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"네가... 10년 전 사라진 내 아버지를 만났다고?","JPN":"そなたが……10年前に消えた我の父に会っただと？","ENG":"You... met my father, who disappeared ten years ago?","TWN":"你說……你見過10年前失蹤的我父親？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"그자는 엘리시온의 경계 밖에서 온 이방인들을 이끌고 있더군요. 정체는 잘 감췄지만 20년이 지나도 변함없는 목소리 때문에 알아챌 수 있었어요.","JPN":"彼はエリシオンの境界の外から来た異邦人を率いていました。正体は上手く隠せていたものの、20年前とまったく同じ声だったので気が付きました。","ENG":"He was leading outsiders who had come from beyond the borders of Elysion. He hid his identity well, but I recognized him from his voice, unchanged even after twenty years.","TWN":"他當時正帶領一群來自艾利森邊界的外邦人。雖然他把身分藏得很好，但那20年都沒有改變的聲音讓我認出了他。"},"stage":{"bg":"CAMP","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"이방인들의 지도자가 무척 젊다는 이야길 듣고서 식량 교섭을 빌미로 자리를 가진 뒤, 독이 든 차를 대접했었답니다.","JPN":"異邦人たちの指導者がとても若いという話を聞き、食糧の交渉を口実にして場を設け、毒入りのお茶をお出ししました。","ENG":"After hearing that the leader of the outsiders was remarkably young, I arranged a meeting under the pretext of negotiating supplies and served him poisoned tea.","TWN":"聽說那些外邦人的領袖非常年輕，我便以糧食談判為藉口與他見面，端上了一杯有毒的茶。"},"stage":{"bg":"CAMP","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"그는 아무렇지 않게 잔을 비우곤 독의 성분을 읊다가... 당신 안부를 묻더군요.","JPN":"彼は平然とお茶を飲み干した後、毒の成分について語ると……あなたの近況を尋ねました。","ENG":"He drained the cup without concern and recited the components of the poison... then asked after your well-being.","TWN":"他卻若無其事地喝完，還說出了毒藥的成分……接著問起你的近況。"},"stage":{"bg":"CAMP","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"자신의 피를 이어받은 그녀를... 잘 부탁한다면서 말이죠.","JPN":"自分の血を引くあなたを……よろしく頼むと。","ENG":"He said to take good care of the girl who inherited his blood.","TWN":"他說希望我好好照顧那個繼承他血脈的孩子。"},"stage":{"bg":"CAMP","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"처음으로 그런 생각이 들었어요.","JPN":"あの時初めて思ったのです。","ENG":"For the first time, I began to wonder.","TWN":"那是我第一次產生那種想法。"},"stage":{"bg":"CAMP","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"만약 멘탈 프린팅 기술이 성자를 완벽히 모방하지 못하는 이유가... 그녀가 성자가 아니기 때문이라면...?","JPN":"メンタル・プリンティング技術が聖者を完璧に模倣できないのは……彼女が聖者ではないからではないか……？","ENG":"If the reason Mental Printing technology couldn't perfectly replicate a Helgon... was because she wasn't one to begin with...?","TWN":"如果智力複印技術無法完美模仿聖者的原因……是因為她根本不是聖者呢？"},"stage":{"bg":"black","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"어쩌면... 지난 세월 동안 들여온 모든 노력이... 한 요정의 장난에 놀아난 꼴일지도 모른다고요.","JPN":"もしかすると……今までの努力は……妖精のいたずらに振り回されていただけなのかもしれないと。","ENG":"Perhaps all the effort I had poured in over the years... had simply been me dancing in the palm of a single fairy's hand.","TWN":"也許……過去這些年的努力……只是被一個精靈的惡作劇耍得團團轉。"},"stage":{"bg":"black","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"하지만 마에스트로는... 자신이 일궈온 모든 위업을, 한낱 작은 가능성 때문에 포기하고 싶지 않았어요.","JPN":"でもマエストロは……自分が積み重ねてきた偉業を、そんな小さな可能性のために放棄したくなかったんです。","ENG":"But Maestra... didn't want to abandon everything she had achieved over such a small possibility.","TWN":"但指揮家並不想因為那一點微小的可能性，就放棄自己至今創造的一切成就。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"요정이란 건 허구일 뿐이며, 내 연구만이 곧 다가올 영원한 겨울의 난제를 풀 수 있을 거라 되뇌었죠.","JPN":"妖精というのは虚構の存在に過ぎず、この研究こそがもうすぐ訪れる永遠の冬の難題を解く唯一の方法だと、自分に言い聞かせました。","ENG":"She kept telling herself that fairies were nothing but fiction, and that only her research could solve the coming calamity of the eternal winter.","TWN":"精靈不過是虛構的存在罷了。我不斷告訴自己，只有我的研究，才能解開即將到來的永恆寒冬之謎。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"하지만 그 결과는 참담했지.","JPN":"だがその結果は惨めなものだった。","ENG":"But the result was disastrous.","TWN":"但結果卻慘不忍睹。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"너를 방조한 나의 탓이다, 네퀴티아.","JPN":"そなたを止めなかった我のせいだ、ネキティア。","ENG":"It was my fault for allowing you to continue, Nequitia.","TWN":"是我放任了你，莉奎蒂亞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":"당신 스스로를 탓한다고 해서 바뀌는 건 없어요.","JPN":"あなた自身を責めたところで何も変わりません。","ENG":"Blaming yourself won't change anything.","TWN":"就算責怪你自己，也改變不了任何事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"그래... 이미 벌어진 참상을 돌이킬 수는 건 아무것도 없겠지.","JPN":"そうだな……起きてしまった惨劇をなかったことにすることはできないだろう。","ENG":"That's right... nothing can undo what has already happened.","TWN":"是啊……沒有任何方法能夠挽回已經發生的慘劇。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"후회가 아닌 결단이 필요할 뿐.","JPN":"必要なものは後悔ではなく決断。","ENG":"What we need is not regret, but resolve.","TWN":"現在需要的不是後悔，而是決斷。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"그러니 마왕이 될 운명의 소녀를... 내 손으로 멈출 것이다.","JPN":"ゆえに我は魔王になる運命の少女を……この手で止めてみせる。","ENG":"So I will stop the girl destined to become the Demon Lord... with my own hands.","TWN":"所以，就由我親手阻止……注定會成為魔王的少女。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_QM","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"마에스트로...","JPN":"マエストロ……","ENG":"Maestra...","TWN":"指揮家……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"낙원에 온 뒤로 여태껏 잠잠하더니... 대체 무슨 말을 하고 있는 거야? 요정이란 건 또 뭐고?","JPN":"楽園に来てしばらく静かだと思ったら……いったい何の話？　妖精ってのは何？","ENG":"You've been quiet ever since we came to the Promised Land... What on earth are you talking about? And what do you mean by fairies?","TWN":"自從來到樂園後一直保持沉默……你到底在說什麼？什麼精靈？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"전 그저, 예하께서 저희를 죽이는 것보다 흥미를 가지실 만한 소재로 이야길 나눴을 뿐이랍니다.","JPN":"私はただ、猊下が私たちを殺すことよりも興味を示しそうな話題を出しただけです。","ENG":"I was simply speaking about something that might interest Her Eminence more than killing us.","TWN":"我只是找了個比起殺掉我們，更可能讓主教感興趣的話題聊聊而已。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"하지만 지금 당신에게 중요한 건 그게 아니죠.","JPN":"ですが今あなたにとって重要なのはそっちではありません。","ENG":"But that isn't what's important to you right now.","TWN":"不過現在對你而言，重要的並不是那個。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이만하면- 시간은 충분히 끈 것 같지 않나요?","JPN":"これで……十分時間稼ぎになったのではありませんか？","ENG":"At this point... Haven't we bought enough time?","TWN":"差不多了吧—時間應該也拖得夠久了，不是嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...뭐?","JPN":"……え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"......!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아!!!","JPN":"エクレシア！！！","ENG":"Ecclesia!!!","TWN":"艾可露西亞！！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};